# Generate self-signed certificate and key if they don't exist
def generate_cert_and_key():
    from cryptography import x509
    from cryptography.x509.oid import NameOID
    from cryptography.hazmat.primitives import hashes
    from cryptography.hazmat.backends import default_backend
    from cryptography.hazmat.primitives.asymmetric import rsa
    from cryptography.hazmat.primitives import serialization
    
    if not os.path.exists('idp_key.pem') or not os.path.exists('idp_cert.pem'):
        key = rsa.generate_private_key(
            public_exponent=65537,
            key_size=2048,
            backend=default_backend()
        )
        
        subject = issuer = x509.Name([
            x509.NameAttribute(NameOID.COUNTRY_NAME, u"US"),
            x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, u"State"),
            x509.NameAttribute(NameOID.LOCALITY_NAME, u"City"),
            x509.NameAttribute(NameOID.ORGANIZATION_NAME, u"MyOrg"),
            x509.NameAttribute(NameOID.COMMON_NAME, u"localhost"),
        ])
        
        cert = x509.CertificateBuilder().subject_name(
            subject
        ).issuer_name(
            issuer
        ).public_key(
            key.public_key()
        ).serial_number(
            x509.random_serial_number()
        ).not_valid_before(
            datetime.utcnow()
        ).not_valid_after(
            datetime.utcnow() + timedelta(days=365)
        ).sign(key, hashes.SHA256(), default_backend())
        
        with open('idp_key.pem', 'wb') as f:
            f.write(key.private_bytes(
                encoding=serialization.Encoding.PEM,
                format=serialization.PrivateFormat.TraditionalOpenSSL,
                encryption_algorithm=serialization.NoEncryption()
            ))
        
        with open('idp_cert.pem', 'wb') as f:
            f.write(cert.public_bytes(serialization.Encoding.PEM))

def load_certificates():
    generate_cert_and_key()
    
    with open('idp_cert.pem', 'r') as f:
        cert_content = f.read()
        cert_lines = cert_content.strip().split('\n')
        cert_lines = [line for line in cert_lines if not line.startswith('-----')]
        SAML_CONFIG['idp']['x509cert'] = ''.join(cert_lines)
    
    with open('idp_key.pem', 'r') as f:
        SAML_CONFIG['idp']['privateKey'] = f.read()

def create_saml_response(user_attributes, audience, recipient, in_response_to=None):
    """Create a SAML Response with signed assertion"""
    
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    session_not_on_or_after = (datetime.utcnow() + timedelta(hours=8)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    assertion_id = '_' + str(uuid.uuid4())
    response_id = '_' + str(uuid.uuid4())
    
    # Build Assertion
    assertion = f"""<saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                    ID="{assertion_id}" 
                    Version="2.0" 
                    IssueInstant="{issue_instant}">
        <saml:Issuer>{SAML_CONFIG['idp']['entityId']}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{user_attributes.get('email', 'user@example.com')}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData NotOnOrAfter="{not_on_or_after}" 
                                              Recipient="{recipient}" 
                                              InResponseTo="{in_response_to or ''}"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{audience}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionNotOnOrAfter="{session_not_on_or_after}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>"""
    
    # Add user attributes
    for attr_name, attr_value in user_attributes.items():
        if isinstance(attr_value, list):
            attr_values = ''.join([f'<saml:AttributeValue>{v}</saml:AttributeValue>' for v in attr_value])
        else:
            attr_values = f'<saml:AttributeValue>{attr_value}</saml:AttributeValue>'
        
        assertion += f"""
            <saml:Attribute Name="{attr_name}" NameFormat="urn:oasis:names:tc:SAML:2.0:attrname-format:basic">
                {attr_values}
            </saml:Attribute>"""
    
    assertion += """
        </saml:AttributeStatement>
    </saml:Assertion>"""
    
    # Sign the assertion
    assertion_tree = etree.fromstring(assertion.encode('utf-8'))
    signed_assertion = OneLogin_Saml2_Utils.add_sign(
        assertion_tree,
        SAML_CONFIG['idp']['privateKey'],
        SAML_CONFIG['idp']['x509cert'],
        algorithm=SAML_CONFIG['security']['signatureAlgorithm'],
        digest_algorithm=SAML_CONFIG['security']['digestAlgorithm']
    )
    
    signed_assertion_str = etree.tostring(signed_assertion, encoding='unicode')
    
    # Build Response
    in_response_to_attr = f'InResponseTo="{in_response_to}"' if in_response_to else ''
    
    response = f"""<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                   xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                   ID="{response_id}" 
                   Version="2.0" 
                   IssueInstant="{issue_instant}" 
                   Destination="{recipient}"
                   {in_response_to_attr}>
        <saml:Issuer>{SAML_CONFIG['idp']['entityId']}</saml:Issuer>
        <samlp:Status>
            <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
        </samlp:Status>
        {signed_assertion_str}
    </samlp:Response>"""
    
    return response

@app.route('/sso', methods=['GET', 'POST'])
def sso():
    """Single Sign-On endpoint"""
    
    # Get SAMLRequest if present (for SP-initiated flow)
    saml_request = request.args.get('SAMLRequest') or request.form.get('SAMLRequest')
    relay_state = request.args.get('RelayState') or request.form.get('RelayState', '')
    
    in_response_to = None
    
    if saml_request:
        try:
            decoded_request = base64.b64decode(saml_request)
            import zlib
            try:
                inflated_request = zlib.decompress(decoded_request, -15)
            except:
                inflated_request = decoded_request
            
            request_tree = etree.fromstring(inflated_request)
            in_response_to = request_tree.get('ID')
            acs_url = request_tree.get('AssertionConsumerServiceURL')
        except Exception as e:
            return f"Error processing SAML Request: {str(e)}", 400
    else:
        # IdP-initiated flow - use default SP ACS URL
        acs_url = SAML_CONFIG['sp']['assertionConsumerService']['url']
    
    # Simulate user authentication (in production, this would be a login form)
    user_attributes = {
        'email': 'user@example.com',
        'firstName': 'John',
        'lastName': 'Doe',
        'groups': ['Users', 'Admins'],
        'uid': '12345'
    }
    
    # Create SAML Response
    saml_response = create_saml_response(
        user_attributes=user_attributes,
        audience=SAML_CONFIG['sp']['entityId'],
        recipient=acs_url,
        in_response_to=in_response_to
    )
    
    # Base64 encode the response
    encoded_response = base64.b64encode(saml_response.encode('utf-8')).decode('utf-8')
    
    # Create HTML auto-submit form
    html_response = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <title>SAML Response</title>
    </head>
    <body onload="document.forms[0].submit()">
        <form method="post" action="{acs_url}">
            <input type="hidden" name="SAMLResponse" value="{encoded_response}" />
            <input type="hidden" name="RelayState" value="{relay_state}" />
            <noscript>
                <input type="submit" value="Continue" />
            </noscript>
        </form>
    </body>
    </html>
    """
    
    return html_response

